import {
  ChangeDetectionStrategy,
  Component,
  OnInit,
  inject,
  signal,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { ApiService, errorMessage } from '../core/api.service';
import { Account, Opportunity, STAGES, Stage } from '../core/models';

@Component({
  selector: 'app-opportunities',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './opportunities.component.html',
  styleUrl: '../shared/list.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class OpportunitiesComponent implements OnInit {
  private readonly api = inject(ApiService);
  readonly stages = STAGES;

  loading = signal(true);
  error = signal<string | null>(null);
  saving = signal(false);

  accounts = signal<Account[]>([]);
  opportunities = signal<Opportunity[]>([]);

  name = signal('');
  amount = signal<number | null>(null);
  stage = signal<Stage>('Prospecting');
  accountId = signal('');

  stageClass(stage: Stage): string {
    return 'stage-' + stage.toLowerCase();
  }

  async ngOnInit(): Promise<void> {
    this.loading.set(true);
    try {
      const [opportunities, accounts] = await Promise.all([
        this.api.listOpportunities(),
        this.api.listAccounts(),
      ]);
      this.opportunities.set(opportunities);
      this.accounts.set(accounts);
      if (accounts[0]) this.accountId.set(accounts[0].id);
    } catch (err) {
      this.error.set(errorMessage(err, 'Could not load opportunities.'));
    } finally {
      this.loading.set(false);
    }
  }

  async create(): Promise<void> {
    this.error.set(null);
    if (!this.name().trim() || !this.amount() || this.amount()! <= 0) {
      this.error.set('Name and a positive amount are required.');
      return;
    }
    if (!this.accountId()) {
      this.error.set('Create an account first, then link the opportunity to it.');
      return;
    }
    this.saving.set(true);
    try {
      const created = await this.api.createOpportunity({
        name: this.name().trim(),
        amount: this.amount()!,
        stage: this.stage(),
        accountId: this.accountId(),
      });
      const acct = this.accounts().find((a) => a.id === this.accountId());
      const opp = { ...created, accountName: acct?.name ?? created.accountName };
      this.opportunities.update((list) => [opp, ...list]);
      this.name.set('');
      this.amount.set(null);
    } catch (err) {
      this.error.set(errorMessage(err, 'Could not create the opportunity.'));
    } finally {
      this.saving.set(false);
    }
  }
}
